module RefModule(
  input clk,
  input reset,
  input data,
  output reg [7:0] count
);reg prev_data;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
      count <= 0;
      prev_data <= 0;
    end else begin
      if (data && !prev_data) begin
        count <= count + 1;
      end
      prev_data <= data;
    end
  end

endmodule
